def dilation_pt(
    x, 
    iteration=1,
    kernel_size=3,
    padding=None):
    for i in range(iteration):
        x = F.max_pool2d(
            x,
            kernel_size=kernel_size,
            stride=1,
            padding=padding)
    return x
        
        

# %% ../../nbs/49_patching.inference_batch_image.ipynb #e648fd04
def erosion_pt(
               x,
               iteration=1,
               kernel_size=3,
                padding=None,
                ):
    neg_ = -x
    for i in range(iteration):
        
    
        neg_ = F.max_pool2d(
            neg_,
            kernel_size=kernel_size,
            stride=1,
            padding=padding)
    return - neg_



