class TiledInferenceModel(nn.Module):
    def __init__(
            self, 
            model, 
            tile_size=256, 
            overlap=32, 
            merge_strategy='confidence_weighted', 
            confidence_threshold=0.5):
        super().__init__()
        self.model = model
        self.tile_size = tile_size
        self.overlap = overlap
        self._tiling= TileProcessorv4(
            tile_size=tile_size,
            overlap=overlap,
        )
        self._tile_merger = TileMergerv4(
            merge_strategy=merge_strategy,
            confidence_threshold=confidence_threshold
        )

    def forward(self, x):
        # Expected x shape: (batch_size, channels, height, width) e.g., (1, 2, 1152, 1632)
        with torch.no_grad():
            tiles, positions = self._tiling(x)
            print(f' tiles has a shape of {tiles.shape}')
            print(f'Tile size: {tiles[0].shape} \n num tiles: {len(tiles)}')
            tiled_predictions = self.model(tiles)
            if isinstance(tiled_predictions, tuple):
                tiled_predictions = tiled_predictions[0]
            pred_x = self._tile_merger(
                            tiled_predictions, 
                            positions,
                            x.shape[2], x.shape[3])
            return pred_x

