class TwoImageModelPyTorch(nn.Module):
    """PyTorch implementation of two-image model compatible with ONNX opset 12"""
    
    def __init__(
        self,
        base_model: nn.Module,
        im1_threshold: float = 0.3,
        pred_threshold: float = 0.5,
        dilation_iteration_rev: int = 2,
        dilation_iteration: int = 2
    ):
        super().__init__()
        self.base_model = base_model
        self.im1_threshold = im1_threshold
        self.pred_threshold = pred_threshold
        self.dilation_iteration_rev = dilation_iteration_rev
        self.dilation_iteration = dilation_iteration
        
        # Define morphological operations using MaxPool2d for dilation
        self.dilation_kernel = nn.MaxPool2d(
            kernel_size=3, 
            stride=1, 
            padding=1
        )
    
    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Forward pass for two-image model
        Args:
            x: Input tensor of shape (B, 2, H, W) where channel 0 is image1, channel 1 is image2
        Returns:
            Output tensor of shape (B, 1, H, W)
        """
        # Split input into image1 and image2
        image1 = x[:, 0:1, :, :]  # Shape: (B, 1, H, W)
        image2 = x[:, 1:2, :, :]  # Shape: (B, 1, H, W)
        
        # Apply threshold to image1 (ONNX-compatible)
        image1_thresh = torch.where(
            image1 > self.im1_threshold,
            torch.ones_like(image1),
            torch.zeros_like(image1)
        )
        
        # Get model prediction on image2
        model_out = self.base_model(image2)
        
        # Apply threshold to model output (ONNX-compatible)
        model_out_thresh = torch.where(
            model_out >= self.pred_threshold,
            torch.ones_like(model_out),
            torch.zeros_like(model_out)
        )
        
        # Multiply model output with thresholded image1
        output = model_out_thresh * image1_thresh
        
        # Reverse dilation: negate output
        revers = -output
        
        # Apply dilation iterations (reverse)
        for _ in range(self.dilation_iteration_rev):
            revers = self.dilation_kernel(revers)
        
        # Negate back
        output = -revers
        
        # Apply final dilation iterations
        for _ in range(self.dilation_iteration):
            output = self.dilation_kernel(output)
        
        # Final multiplication with original model output
        final_output = model_out_thresh * output

        # final removal of small objects + fill the whole
        kernel_size=3
        padding=kernel_size//3
        # dilation 2 times to fill holes
        dilated_msk = dilation_pt(
            final_output, 
           kernel_size=kernel_size,
           padding=padding,
           iteration=2)

        # erosion 4 times to remove small objects
        eroted_msk = erosion_pt(
                    dilated_msk,
                    kernel_size=kernel_size,
                   padding=padding,
                   iteration=4)
        # dilation again 2 times to make same size
        dialted_msk2 = dilation_pt(
                        eroted_msk,
                        kernel_size=kernel_size,
                        padding=padding,
                        iteration=2)
        
        return dialted_msk2
        

def create_two_image_model_pytorch(
    base_model: nn.Module,
    im1_threshold: float = 0.3,
    pred_threshold: float = 0.5,
    dilation_iteration_rev: int = 2,
    dilation_iteration: int = 2,
    save_path: str = None
) -> TwoImageModelPyTorch:
    """
    Create PyTorch two-image model from base model
    
    Args:
        base_model: Base PyTorch model for single image inference
        im1_threshold: Threshold for image1 binarization
        pred_threshold: Threshold for model prediction binarization
        dilation_iteration_rev: Number of reverse dilation iterations
        dilation_iteration: Number of final dilation iterations
        save_path: Optional path to save the model
    
    Returns:
        TwoImageModelPyTorch instance
    """
    model = TwoImageModelPyTorch(
        base_model=base_model,
        im1_threshold=im1_threshold,
        pred_threshold=pred_threshold,
        dilation_iteration_rev=dilation_iteration_rev,
        dilation_iteration=dilation_iteration
    )
    
    if save_path is not None:
        print('=' * 42)
        print('Model saving started')
        Path(save_path).parent.mkdir(parents=True, exist_ok=True)
        torch.save(model.state_dict(), save_path)
        print('Model saving done')
        print('=' * 42)
    
    return model


# %% ../../nbs/49_patching.inference_batch_image.ipynb #64886538
def export_to_onnx(
    model: nn.Module,
    input_shape: tuple = (1, 2, 1152, 1632),
    onnx_path: str = None,
    opset_version: int = 12
):
    """
    Export PyTorch model to ONNX format
    
    Args:
        model: PyTorch model to export
        input_shape: Input tensor shape (B, C, H, W)
        onnx_path: Path to save ONNX model
        opset_version: ONNX opset version (default: 12)
    """
    model.eval()
    dummy_input = torch.randn(*input_shape)
    
    torch.onnx.export(
        model,
        dummy_input,
        onnx_path,
        export_params=True,
        opset_version=opset_version,
        do_constant_folding=True,
        input_names=['input'],
        output_names=['output'],
        dynamic_axes={
            'input': {0: 'batch_size'},
            'output': {0: 'batch_size'}
        }
    )
    print(f'Model exported to ONNX: {onnx_path}')

