def load_whole_pipeline_model(
    model_path: str,
    in_channels:int=1,
    out_channels:int=1,
    tile_size:int=256,
    overlap:int=32,
    im1_threshold:float=0.3,
    pred_threshold:float=0.5,
    dilation_iteration_rev:int=2,
    dilation_iteration:int=2,
    map_location: str = 'cpu',
    edge_model:bool=False,
    dropout_p:float=0.1,
    convert_to_onnx: bool = False,
    onnx_path: str = None,
    opset_version: int = 12,
    input_shape: tuple = (1, 2, 1152, 1632)
):
    "Load the whole pipeline model with optional ONNX conversion"
    model_ = load_end_test_model_only_model(
        in_channels=in_channels,
        out_channels=out_channels,
        model_path=model_path,
        map_location=map_location,
        edge_model=edge_model,
        dropout_p=dropout_p
    )
    tiled_model = TiledInferenceModel(
        model=model_,
        tile_size=tile_size,
        overlap=overlap
    )
    two_img_model = create_two_image_model_pytorch(
        base_model=tiled_model,
        im1_threshold=im1_threshold,
        pred_threshold=pred_threshold,
        dilation_iteration_rev=dilation_iteration_rev,
        dilation_iteration=dilation_iteration
    )
    two_img_model.eval()
    
    # Convert to ONNX if requested
    if convert_to_onnx:
        if onnx_path is None:
            onnx_path = f"{Path(model_path).stem}_whole_pipeline.onnx"
        
        export_to_onnx(
            model=two_img_model,
            input_shape=input_shape,
            onnx_path=onnx_path,
            opset_version=opset_version
        )
    
    return two_img_model

