class InferenceTwoImageDataset(Dataset):
	def __init__(
			self, 
			im1_files:list, 
			im2_files:list,
			transform:Callable=None,
			img_size:tuple=(1152,1632),
			max_tries:int=2
			):
		store_attr()
		
		# Find common files between im1 and im2 based on filename matching
		self._find_common_files(im1_files, im2_files)
		
		self.im1_path = Path(im1_files[0]).parent
		self.im2_path = Path(im2_files[0]).parent
		self.max_tries = max_tries
		
		if transform is None:
			self.transform = transforms.Compose([
				transforms.Resize(img_size),
				transforms.ToTensor()
			])
		else:
			self.transform = transform

	def _find_common_files(self, im1_files:list, im2_files:list):
		"""Find common files between im1 and im2 directories based on filename matching"""
		# Extract base names for comparison
		im1_names = {Path(f).name.replace('image1', 'image2'): f for f in im1_files}
		im2_names = {Path(f).name: f for f in im2_files}
		
		# Find intersection
		common_names = set(im1_names.keys()) & set(im2_names.keys())
		
		# Create matched pairs
		self.im1_files = [im1_names[name] for name in common_names]
		self.im2_files = [im2_names[name] for name in common_names]
		
		# Sort to ensure consistent ordering
		paired_files = list(zip(self.im1_files, self.im2_files))
		paired_files.sort(key=lambda x: Path(x[1]).name)
		self.im1_files, self.im2_files = zip(*paired_files) if paired_files else ([], [])
		self.im1_files, self.im2_files = list(self.im1_files), list(self.im2_files)
		
		# Log the results
		total_im1 = len(im1_files)
		total_im2 = len(im2_files)
		common_count = len(self.im1_files)
		
		print(f"Dataset Statistics:")
		print(f"  Total image1 files: {total_im1}")
		print(f"  Total image2 files: {total_im2}")
		print(f"  Common paired files: {common_count}")
		print(f"  Missing pairs: {max(total_im1, total_im2) - common_count}")
		
		if common_count == 0:
			raise ValueError("No common files found between im1 and im2 directories!")
		
		if common_count < min(total_im1, total_im2):
			print(f"Warning: Only {common_count}/{min(total_im1, total_im2)} files have pairs")

	__repr__ = basic_repr(['im1_path', 'im2_path', 'num_pairs'])
	
	@property
	def num_pairs(self):
		return len(self.im1_files)

	def __len__(self):
		return len(self.im1_files)
		
	def __getitem__(self, idx):
		im1_file = self.im1_files[idx]
		im2_file = self.im2_files[idx]

		for attempt in range(self.max_tries):
			try:
				im1_img = Image.open(im1_file).convert('L')
				im2_img = Image.open(im2_file).convert('L')

				im1_img = self.transform(im1_img)
				im2_img = self.transform(im2_img)
				original_size = im2_img.size
				comb_img = torch.cat((im1_img, im2_img), dim=0)

				if torch.isnan(comb_img).any() or torch.isinf(comb_img).any():
					raise ValueError(f'Invalid image pair {im1_file} & {im2_file}')
			
				return {
					'image': comb_img,
					'im1_file': str(im1_file),
					'im2_file': str(im2_file),
					'original_size': original_size,
					'attempt':attempt
				}

			except Exception as e:
				print(f'Error loading image pair {im1_file} & {im2_file}: {e}')
				if attempt == self.max_tries - 1:
					dummy_tensor = torch.zeros(2, *self.transform.transforms[0].size[::-1])
					return {
						'image': dummy_tensor,
						'im1_file': str(im1_file),
						'im2_file': str(im2_file),
						'error': True
					}


