def segmentation_collate_fn(
        batch: List[Dict[str, Any]]) -> Dict[str, Any]:
    """
    Custom collate function for medical image segmentation batch processing.
    
    Handles:
    - Variable image sizes
    - Error cases (corrupted images)
    - Metadata preservation
    
    Args:
        batch: List of dictionaries from ImageDataset.__getitem__()
               Each dict contains: {'image': tensor, 'path': str, 'original_size': tuple, 'error': bool (optional)}
    
    Returns:
        Dict containing batched data with proper error handling
    """
    
    # Separate valid and error samples
    non_corrupted_samples = []
    corrupted_samples = []
    
    for i, sample in enumerate(batch):
        if sample.get('error', False):
            corrupted_samples.append((i, sample))
        else:
            non_corrupted_samples.append((i, sample))
    
    # If no valid samples, return error batch
    if not non_corrupted_samples:
        return {
            'image': torch.stack([sample['image'] for _, sample in corrupted_samples]),
            'path': [sample['path'] for _, sample in corrupted_samples],
            'original_size': [sample['original_size'] for _, sample in corrupted_samples],
            'batch_indices': [i for i, _ in corrupted_samples],
            'all_errors': True,
            'non_corrupted_samples': torch.zeros(len(batch), dtype=torch.bool)
        }
    
    # Process valid samples
    images = []
    im1_paths = []
    im2_paths = []
    original_sizes = []
    batch_indices = []
    
    for i, sample in non_corrupted_samples:
        images.append(sample['image'])
        im1_paths.append(sample['im1_file'])
        im2_paths.append(sample['im2_file'])
        original_sizes.append(sample['original_size'])
        batch_indices.append(i)
    
    # Stack images (assumes same size after transform)
    try:
        stacked_images = torch.stack(images)
    except Exception as e:
        # Handle different sizes by padding to max size
        print(f"Warning: Image size mismatch in batch, applying padding: {e}")
        stacked_images = pad_images_to_same_size(images)
    
    # Create validity mask for the entire batch
    valid_mask = torch.zeros(len(batch), dtype=torch.bool)
    for i, _ in non_corrupted_samples:
        valid_mask[i] = True
    
    # Prepare batch dictionary
    collated_batch = {
        'image': stacked_images,
        'im1_file': im1_paths,
        'im2_file': im2_paths,
        'original_size': original_sizes,
        'batch_indices': batch_indices,
        'valid_mask': valid_mask,
        'all_errors': False
    }
    
    # Add error information if there are any
    if corrupted_samples:
        collated_batch['error_indices'] = [i for i, _ in corrupted_samples]
        collated_batch['error_paths'] = [sample['path'] for _, sample in corrupted_samples]
        collated_batch['has_errors'] = True
    else:
        collated_batch['has_errors'] = False
    
    return collated_batch

