def post_process_mask(
		mask:np.ndarray, 
		threshold:float=0.5,
		original_size:tuple=None)->Image.Image: # So image size will be width, height
	"""
	Post process the mask and convert to pil image (to 255 scale)
	"""

	if isinstance(mask, torch.Tensor):
		pred = mask.detach().cpu().numpy()

	#print(f' len(pred.shape): {len(pred.shape)} and pred.shape[0]=: {pred.shape[0]}')

	# Handle multi-class
	if len(pred.shape) == 3 and pred.shape[0] > 1:
		pred_ = np.argmax(pred, axis=0)

	# single class

	elif len(pred.shape) == 3 and pred.shape[0] == 1:
		pred_ = pred[0]

	# In case of not thresholded
	if pred_.dtype in [np.float32, np.float64]:
		pred_ = (pred_ > threshold).astype(np.uint8) * 255

	# Convert to pil image
	mask_ = Image.fromarray(pred_)
	if original_size is not None:
		mask_ = mask_.resize(original_size, resample=Image.Resampling.NEAREST)
	return mask_


