def predict_batch(
        image_batch:dict, # dictionary with image and im2_file
		model:nn.Module, # model to use for prediction Normally two image model
		device:str='cpu', # device to use for prediction
		output_dir:str=None, # directory to save the results
		post_process:bool=True, # if True, post process the mask
		threshold:float=0.5, # threshold for post processing
		original_size:tuple=None, # original size of the image
		print_stats:bool=False # if True, print the stats of the mask
	):
	'Process each batch and save the results'

	batch_res = []
	images = image_batch['image'].to(device)
	print(images.shape)
	model = model.to(device)
	im2_files = image_batch['im2_file']

	with torch.no_grad():
		predictions = model(images)
		#print(f'prediction type: {type(predictions)}')
		#if isinstance(predictions, (list, tuple, torch.Tensor)):
			#preds = predictions[0]
		#elif isinstance(predictions, dict):
			#preds = predictions['out']

		# process each file
		for i in range(len(im2_files)):
			if 'error' in image_batch and i < len(image_batch.get('error',[])) :
				continue
			try:
				# Get prediction for this image
				pred = predictions[i]

				# if in case of post processing
				mask = post_process_mask(
					pred,
					threshold=threshold,
					original_size=original_size
				)
				# Print mask statistics
				mask_array = np.array(mask)
				unique_vals, counts = np.unique(mask_array, return_counts=True)
				total_pixels = mask_array.size

				im_path = im2_files[i]
				if print_stats:
					print(f"Mask stats for {Path(im_path).name}:")
					print(f"  Shape: {mask_array.shape}")
					print(f"  Unique values: {unique_vals}")
					print(f"  Pixel counts: {dict(zip(unique_vals, counts))}")
					print(f"  Foreground ratio: {counts[-1]/total_pixels:.4f}" if len(counts) > 1 else "  No foreground pixels")

				# Save the mask
				basename = Path(im_path).stem
				if output_dir is None:
					output_dir = 'data'
				
				output_path = Path(output_dir, f'{basename}.png')
				Path(output_path).parent.mkdir(parents=True, exist_ok=True)
				mask.save(output_path)
				batch_res.append({
					'input': im_path,
					'output': output_path,
					'status': 'success'
				})
			except Exception as e:
				batch_res.append({
					'input': im_path,
					'output': None,
					'status': 'error',
					'error': e
				})

	return batch_res

