def process_image_pair_chunks(
	model:nn.Module,
	im1_files:List[str],
	im2_files:List[str],
	batch_size:int,
	num_workers:int,
	device:str,
	post_process:bool=True,
	threshold:float=0.5,
	original_size:tuple=None,
	print_stats:bool=False,
	output_dir:str=None,
	
):
	'Process image pairs in chunks'
	
	inf_ds = InferenceTwoImageDataset(
		im1_files=im1_files,
		im2_files=im2_files,
		max_tries=2
	)
	inf_dl = create_pin_dl(
		ds=inf_ds,
		shuffle=False,
		num_workers=num_workers,
		collate_fn=segmentation_collate_fn,
		pin_memory=True,
		batch_size=batch_size
	)

	print(f"🔄 Processing {len(inf_dl)} batches")
	
	results = []
	with torch.no_grad():
		for batch_idx, batch in enumerate(inf_dl):
			try:
				batch_res = predict_batch(
					image_batch=batch,
					model=model,
					device=device,
					output_dir=output_dir,
					post_process=post_process,
					threshold=threshold,
					original_size=original_size,
					print_stats=print_stats
				)
				results.append(batch_res)
				if (batch_idx + 1) % 10 == 0:
					print(f"✅ Processed {batch_idx + 1}/{len(inf_dl)} batches")
					
			except Exception as e:
				print(f"❌ Error processing batch {batch_idx}: {e}")
				continue
				
	return results

