@call_parse
def main_(
        model_path:Param(type=str, help='Path to the model file')='/model/path',
        im1_files_path:Param(type=str, help='A text file containing the list of IM1 files')='/im1/file/list.txt',
        im2_files_path:Param(type=str, help='A text file containing the list of IM2 files')='/im2/file/list.txt',
        output_dir:Param(type=str, help='Output directory')='/output/dir',
		pred_output_dir:Param(type=str, help='Prediction output directory')='/pred/output/dir',
        batch_size:Param(type=int, help='Batch size')='1',
        num_workers:Param(type=int, help='Number of workers')='0',
        img_size:Param(type=tuple, help='Image size')=(1152,1632),
        device:Param(type=str, help='Device')='cpu',
        python_env:Param(type=str, help='Python environment')='None',
        additional_args:Param(type=str, help='Additional arguments')='',
		overlap:Param(type=int, help='Overlap between tiles')=32,
		tile_size:Param(type=int, help='Tile size')=256,
		im1_threshold:Param(type=float, help='IM1 threshold')=0.3,
		edge_model:Param(type=bool, help='Edge model')=False,
		pred_threshold:Param(type=float, help='Prediction threshold')=0.5,
		dilation_iteration_rev:Param(type=int, help='Dilation iteration reverse')=2,
		dilation_iteration:Param(type=int, help='Dilation iteration')=2,
		map_location:Param(type=str, help='Map location')='cpu',
		convert_to_onnx:Param(type=bool, help='Convert to ONNX',action=store_true)=False,
		onnx_path:Param(type=str, help='ONNX path')='None',
		opset_version:Param(type=int, help='ONNX opset version')=12,
		input_shape:Param(type=tuple, help='Input shape')=(1,2,1152,1632),
	):
	'End to end pipeline script for inference'
	# load model
	model = load_whole_pipeline_model(
		model_path,
		in_channels=1,
		out_channels=1,
		tile_size=tile_size,
		overlap=overlap,
		im1_threshold=im1_threshold,
		pred_threshold=pred_threshold,
		dilation_iteration_rev=dilation_iteration_rev,
		dilation_iteration=dilation_iteration,
		map_location=device,
		convert_to_onnx=convert_to_onnx,
		onnx_path=onnx_path,
		opset_version=opset_version,
		input_shape=input_shape,
		edge_model=edge_model
		)
	

	model.eval()
	pred_output_dir = Path(pred_output_dir)
	pred_output_dir.mkdir(exist_ok=True, parents=True)

	# load files 
	im1_files = load_file_list(im1_files_path)
	im2_files = load_file_list(im2_files_path)

	# process image pairs in chunks
	results = process_image_pair_chunks(
		model=model,
		im1_files=im1_files,
		im2_files=im2_files,
		batch_size=batch_size,
		num_workers=num_workers,
		device=device,
		post_process=True,
		threshold=pred_threshold,
		original_size=None,
		print_stats=True,
		output_dir=pred_output_dir
	)
	

